import React from 'react';
import { MapPin, Package, truck, CheckCircle, Clock } from 'lucide-react';

const SeguimientoPedido = ({ pedido }) => {
  // Definimos las etapas del pedido
  const etapas = [
    { id: 'proceso', label: 'Preparando', icon: <Package size={20} /> },
    { id: 'camino', label: 'En camino', icon: <truck size={20} /> },
    { id: 'completado', label: 'Entregado', icon: <CheckCircle size={20} /> }
  ];

  const getIndex = (estado) => etapas.findIndex(e => e.id === estado);
  const pasoActual = getIndex(pedido.estado);

  return (
    <div style={card}>
      <div style={header}>
        <div style={statusBadge}>{pedido.estado.toUpperCase()}</div>
        <span style={date}>{new Date(pedido.createdAt).toLocaleTimeString()}</span>
      </div>

      <div style={stepper}>
        {etapas.map((etapa, index) => (
          <div key={etapa.id} style={stepWrapper}>
            <div style={index <= pasoActual ? circleActive : circleInactive}>
              {etapa.icon}
            </div>
            <span style={index <= pasoActual ? labelActive : labelInactive}>{etapa.label}</span>
            {index < etapas.length - 1 && <div style={line} />}
          </div>
        ))}
      </div>

      <div style={details}>
        <div style={row}><MapPin size={16}/> <span>{pedido.local?.nombre}</span></div>
        <div style={row}><Clock size={16}/> <span>Llega en aprox. 15-20 min</span></div>
      </div>
      
      <div style={itemsList}>
        {pedido.items.map((item, idx) => (
          <div key={idx} style={itemRow}>{item.cantidad}x {item.producto}</div>
        ))}
      </div>
    </div>
  );
};

// Estilos rápidos
const card = { background: 'white', padding: '20px', borderRadius: '18px', marginBottom: '15px', border: '1px solid #e2e8f0' };
const header = { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' };
const statusBadge = { background: '#fff3e0', color: '#e67e22', padding: '4px 12px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 'bold' };
const date = { color: '#a0aec0', fontSize: '0.8rem' };
const stepper = { display: 'flex', justifyContent: 'space-between', position: 'relative', marginBottom: '25px', padding: '0 10px' };
const stepWrapper = { display: 'flex', flexDirection: 'column', alignItems: 'center', zIndex: 2, flex: 1 };
const circleActive = { width: '40px', height: '40px', borderRadius: '50%', background: '#e67e22', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const circleInactive = { width: '40px', height: '40px', borderRadius: '50%', background: '#edf2f7', color: '#a0aec0', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const labelActive = { fontSize: '0.7rem', marginTop: '8px', color: '#e67e22', fontWeight: 'bold' };
const labelInactive = { fontSize: '0.7rem', marginTop: '8px', color: '#a0aec0' };
const line = { position: 'absolute', top: '20px', width: '80%', height: '2px', background: '#edf2f7', zIndex: -1 };
const details = { borderTop: '1px solid #f1f5f9', paddingTop: '15px', display: 'flex', gap: '20px', fontSize: '0.85rem', color: '#4a5568' };
const row = { display: 'flex', alignItems: 'center', gap: '5px' };
const itemsList = { marginTop: '10px', fontSize: '0.8rem', color: '#718096' };
const itemRow = { padding: '2px 0' };

export default SeguimientoPedido;
